 1	import { Request, Response, NextFunction } from 'express';
 2	import { verifyToken } from '../utils/jwt';
 3	
 4	export function authMiddleware(req: Request, res: Response, next: NextFunction) {
 5	  const token = req.headers.authorization?.split(' ')[1];
 6	  if (!token) {
 7	    return res.status(401).json({ error: 'No token provided' });
 8	  }
 9	  try {
10	    const decoded = verifyToken(token);
11	    req.user = decoded;
12	    next();
13	  } catch (err) {
14	    return res.status(403).json({ error: 'Invalid token' });
15	  }
16	}
